import * as React from 'react';
import { useKey } from 'react-use';
import { GatsbyImage, getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import { Link } from './common/link';

const Mainvisual = data => {
  const img = data.images.allFile.edges;

  const containerRef = React.useRef(null);
  const [clientHeight, setClientHeight] = React.useState();
  const [current, setCurrent] = React.useState(
    Math.floor(Math.random() * img.length)
  );
  const [willShow, setWillShow] = React.useState(true);

  const prev = () =>
    setCurrent(current => {
      const _current = current === 0 ? img.length - 1 : current - 1;
      return _current;
    });
  const next = () => setCurrent(current => (current + 1) % img.length);

  useKey('ArrowUp', prev);
  useKey('ArrowLeft', prev);
  useKey('ArrowRight', next);
  useKey('ArrowDown', next);

  const onTransitionEnd = () => {
    if (!willShow) {
      // 消えた時の処理
      const _current = (current + 1) % img.length;

      setCurrent(_current);

      setTimeout(() => {
        // console.log('timeout');
        setWillShow(true);
      }, 100);
    } else {
      // @TODO
      setTimeout(() => {
        setWillShow(false);
      }, 3500);
    }
  };

  React.useEffect(() => {
    const update = () => {
      const { width, height } = getImage(img[current].node);

      const aspectRatio = width / height;

      // ヘッダーの2倍を引き適切なアスペクト比に
      const newWidth = (clientHeight - 160) * aspectRatio;
      containerRef.current.style.width = newWidth + 'px';
    };

    const updateClientHeight = () => {
      setClientHeight(document.documentElement.clientHeight);
    };

    window.addEventListener('resize', updateClientHeight);
    window.addEventListener('load', updateClientHeight);

    updateClientHeight();
    update();

    return () => {
      window.removeEventListener('resize', updateClientHeight);
      window.removeEventListener('load', updateClientHeight);
    };
  }, [img, current, clientHeight]);

  const [, _link] = img[current].node.relativePath.match(
    // @NOTE 2023.06.11 順番を柔軟に変更するためファイル名チェックを外す
    // /^mainvisuals\/\d{2}_(.+)\.(.+)$/
    /^mainvisuals\/.+_(.+)\..+$/
  );

  return (
    <Box
      component='section'
      sx={{
        position: 'relative',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        width: '100%',
        mt: 10,
        height: 'calc(100vh - 160px)',
        // eslint-disable-next-line no-dupe-keys
        height: 'calc(100dvh - 160px)'
      }}
    >
      <Box
        ref={containerRef}
        sx={{
          position: 'relative',
          height: '100%',
          overflow: 'hidden'
        }}
      >
        <Box
          onTransitionEnd={onTransitionEnd}
          sx={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            zIndex: 5,
            transition: 'opacity 1000ms ease-out',
            opacity: willShow ? 1 : 0
          }}
        >
          <Link href={`/works/${_link}/`}>
            <GatsbyImage
              image={getImage(img[current].node)}
              alt='YUHEI ONO'
              layout='fullWidth'
              placeholder='blurred'
              style={{
                pointerEvents: 'none',
                userSelect: 'none'
              }}
            />
          </Link>
        </Box>
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            zIndex: -1
          }}
        >
          <GatsbyImage
            image={getImage(img[(current + 1) % img.length].node)}
            alt='preload'
            layout='fullWidth'
            style={{
              opacity: 0,
              visibility: 'hidden',
              pointerEvents: 'none',
              userSelect: 'none'
            }}
          />
        </Box>
      </Box>
    </Box>
  );
};

export default Mainvisual;
